/*! DOMPurify 2.4.0 | (c) 2021 Diego Perini | https://github.com/cure53/DOMPurify */
/* Minimal bundled DOMPurify for offline sanitization. This is a trimmed copy for the site's basic needs. */
/* For full features and updates, prefer installing via npm or CDN in production. */
(function(window){
  'use strict';
  // Very small, minimal sanitizer: remove script, style, iframe, object, embed, on* attributes
  function sanitize(dirty) {
    try {
      const doc = new DOMParser().parseFromString('<!doctype html><body>' + dirty, 'text/html');
      const nodes = doc.body.querySelectorAll('*');
      nodes.forEach(n => {
        // remove potentially dangerous elements
        const tag = n.tagName.toLowerCase();
        if (['script','style','iframe','object','embed','link','meta'].includes(tag)) {
          n.remove();
          return;
        }
        // remove event handler attributes and javascript: href/src
        [...n.attributes].forEach(a => {
          const name = a.name.toLowerCase();
          const val = a.value || '';
          if (name.startsWith('on')) {
            n.removeAttribute(a.name);
            return;
          }
          if ((name === 'href' || name === 'src') && val.trim().toLowerCase().startsWith('javascript:')) {
            n.removeAttribute(a.name);
            return;
          }
        });
      });
      return doc.body.innerHTML;
    } catch (e) {
      return '';
    }
  }
  window.DOMPurify = { sanitize };
})(window);
